const fs = require("fs");
const path = require("path");

const artifactPath = path.join(
  __dirname,
  "..",
  "artifacts",
  "contracts",
  "PlopsBondingToken.sol",
  "PlopsBondingToken.json",
);
const artifact = JSON.parse(fs.readFileSync(artifactPath, "utf8"));

const outDir = path.join(__dirname, "..", "..", "src", "contracts");
fs.mkdirSync(outDir, { recursive: true });

const header =
  "// AUTO-GENERATED by contracts/scripts/export-artifact.cjs — do not edit by hand.\n" +
  "// Source: contracts/contracts/PlopsBondingToken.sol\n";

const content =
  header +
  `export const PLOPS_TOKEN_ABI = ${JSON.stringify(artifact.abi, null, 2)} as const;\n\n` +
  `export const PLOPS_TOKEN_BYTECODE = ${JSON.stringify(artifact.bytecode)} as const;\n`;

const outFile = path.join(outDir, "PlopsBondingToken.ts");
fs.writeFileSync(outFile, content);
console.log("Wrote", outFile, `(${content.length} bytes)`);
